export function initDropZone(dropZoneElement, dotNetHelper) {
    function onDragOver(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.add("drag-over");
    }

    function onDragLeave(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.remove("drag-over");
    }

    function onDrop(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.remove("drag-over");

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || "unknown"
        }));

        dotNetHelper.invokeMethodAsync("OnFilesDropped", files);
    }

    dropZoneElement.addEventListener("dragover", onDragOver);
    dropZoneElement.addEventListener("dragleave", onDragLeave);
    dropZoneElement.addEventListener("drop", onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener("dragover", onDragOver);
            dropZoneElement.removeEventListener("dragleave", onDragLeave);
            dropZoneElement.removeEventListener("drop", onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone">
    <p>Drag &amp; drop files here</p>
</div>

@if (_droppedFiles.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _droppedFiles)
        {
            <li class="file-entry">
                @if (entry.Size > MaxFileSizeBytes)
                {
                    <div class="file-error">
                        <strong>@entry.Name</strong> &mdash; @FormatSize(entry.Size) (@entry.Type)
                        <span class="error-message">File exceeds the 10 MB limit.</span>
                    </div>
                }
                else
                {
                    <div class="file-info">
                        <strong>@entry.Name</strong> &mdash; @FormatSize(entry.Size) (@entry.Type)
                    </div>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;
    private readonly List<FileInfo> _droppedFiles = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/fileDropZone.js");
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initDropZone", _dropZoneRef, DotNetObjectReference.Create(this));
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> files)
    {
        _droppedFiles.AddRange(files);
        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileInfo file)
    {
        _droppedFiles.Remove(file);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _droppedFiles.Where(f => f.Size <= MaxFileSizeBytes).ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F2} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1.1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

::deep .drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-info {
    flex: 1;
}

.file-error {
    flex: 1;
    color: #842029;
}

.error-message {
    display: inline-block;
    margin-left: 0.5rem;
    font-weight: 600;
}

.btn-remove {
    margin-left: 1rem;
    padding: 0.25rem 0.75rem;
    border: 1px solid #dc3545;
    border-radius: 4px;
    background: transparent;
    color: #dc3545;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

